import { readFile, writeFile } from "node:fs/promises";
import path from "node:path";
import { pathToFileURL } from "node:url";

const repoRoot = path.resolve(import.meta.dirname, "..");

globalThis.window = {};
await import(pathToFileURL(path.join(repoRoot, "exercise-data.js")));

const course = globalThis.window.COURSE_DATA;
const solutionCode = {};

for (const chapter of course.chapters) {
  for (const exercise of chapter.exercises) {
    solutionCode[exercise.id] = await readFile(path.join(repoRoot, exercise.file), "utf8");
  }
}

const banner = "// Generated by scripts/build-solution-bundle.mjs. Do not edit by hand.\n";
const output = `${banner}window.SOLUTION_CODE = ${JSON.stringify(solutionCode, null, 2)};\n`;

await writeFile(path.join(repoRoot, "solution-code.js"), output, "utf8");
console.log(`Bundled ${Object.keys(solutionCode).length} Python solutions.`);
